  <div class="warning-toast" id="warning-toast"></div>

  <script>
    document.addEventListener('DOMContentLoaded', () => {
      // Biến
      let totalPoints = 0;
      let remainingPoints = 0;
      let currentPage = 0;
      const totalPages = 5;
      let hasPartner = false;

      // Phần tử
      const totalPointsEl = document.getElementById('total-points');
      const remainingPointsEl = document.getElementById('remaining-points');
      const rollBtn = document.getElementById('roll-btn');
      const pagesContainer = document.getElementById('pages-container');
      const pageIndicator = document.getElementById('page-indicator');
      const prevBtn = document.getElementById('prev-btn');
      const nextBtn = document.getElementById('next-btn');
      const submitBtn = document.getElementById('submit-btn');
      const noPartnerBtn = document.getElementById('no-partner-btn');
      const hasPartnerBtn = document.getElementById('has-partner-btn');
      const partnerOptions = document.getElementById('partner-options');
      const penisSection = document.getElementById('penis-section');
      const warningToast = document.getElementById('warning-toast');
      const convertInput = document.getElementById('convert-points');
      const convertGold = document.getElementById('convert-gold');
      const previewBox = document.getElementById('preview-box');

      // Hiển thị cảnh báo
      function showWarning(msg) {
        warningToast.textContent = msg;
        warningToast.classList.add('show');
        setTimeout(() => warningToast.classList.remove('show'), 2000);
      }

      // Cập nhật hiển thị điểm
      function updatePoints() {
        remainingPointsEl.textContent = remainingPoints;
        remainingPointsEl.classList.remove('negative');
        if (remainingPoints < 0) {
          remainingPointsEl.classList.add('negative');
          submitBtn.disabled = true;
        } else {
          submitBtn.disabled = false;
        }
        // Cập nhật giới hạn chuyển đổi
        convertInput.max = Math.max(0, remainingPoints);
        if (parseInt(convertInput.value) > remainingPoints) {
          convertInput.value = Math.max(0, remainingPoints);
          convertGold.textContent = convertInput.value;
        }
      }

      // Tính tổng tiêu hao
      function calculateTotalCost() {
        let cost = 0;

        // Nút chọn một (không bao gồm phần bạn đời)
        document.querySelectorAll('.select-btn.selected:not(.multi):not(#partner-options .select-btn)').forEach(btn => {
          cost += parseInt(btn.dataset.cost) || 0;
        });

        // Nút chọn nhiều (không bao gồm phần bạn đời)
        document.querySelectorAll('.select-btn.multi.selected:not(#partner-options .select-btn)').forEach(btn => {
          cost += parseInt(btn.dataset.cost) || 0;
        });

        // Liên quan đến bạn đời
        if (hasPartner) {
          partnerOptions.querySelectorAll('.select-btn.selected:not(.multi)').forEach(btn => {
            cost += parseInt(btn.dataset.cost) || 0;
          });
          partnerOptions.querySelectorAll('.select-btn.multi.selected').forEach(btn => {
            cost += parseInt(btn.dataset.cost) || 0;
          });
        }

        remainingPoints = totalPoints - cost;
        updatePoints();
        updatePreview();
      }

      // Chuyển trang
      function goToPage(page) {
        if (page < 0 || page >= totalPages) return;
        currentPage = page;
        pagesContainer.style.transform = `translateX(-${page * 100}%)`;

        // Cập nhật chỉ báo
        document.querySelectorAll('.dot').forEach((dot, i) => {
          dot.classList.toggle('active', i === page);
        });

        // Cập nhật nút điều hướng
        prevBtn.disabled = page === 0;
        if (page === totalPages - 1) {
          nextBtn.classList.add('hidden');
        } else {
          nextBtn.classList.remove('hidden');
        }
      }

      // Roll điểm
      rollBtn.addEventListener('click', () => {
        totalPoints = Math.floor(Math.random() * 201) + 1000;
        remainingPoints = totalPoints;
        totalPointsEl.textContent = totalPoints;
        rollBtn.textContent = '🎲 Roll Lại';
        calculateTotalCost();
      });

      // Nút điều hướng
      prevBtn.addEventListener('click', () => goToPage(currentPage - 1));
      nextBtn.addEventListener('click', () => {
        if (totalPoints === 0) {
          showWarning('Vui lòng Roll điểm trước!');
          return;
        }
        goToPage(currentPage + 1);
      });

      // Nhấp vào chỉ báo trang
      document.querySelectorAll('.dot').forEach(dot => {
        dot.addEventListener('click', () => {
          if (totalPoints === 0) {
            showWarning('Vui lòng Roll điểm trước!');
            return;
          }
          goToPage(parseInt(dot.dataset.page));
        });
      });

      // Nhấp vào nút chọn một
      document.querySelectorAll('.select-btn:not(.multi)').forEach(btn => {
        btn.addEventListener('click', () => {
