    </div>
    <div class="content-area">
      <div class="tab-content active" id="tab-events"><div class="loading">Đang tải sự kiện...</div></div>
      <div class="tab-content" id="tab-family"><div class="loading">Đang tải thành viên...</div></div>
      <div class="tab-content" id="tab-info"><div class="loading">Đang tải thông tin...</div></div>
      <div class="tab-content" id="tab-shop"><div class="loading">Đang tải cửa hàng...</div></div>
      <div class="tab-content" id="tab-grave"><div class="loading">Đang tải nghĩa trang...</div></div>
      <div class="tab-content" id="tab-detailed"><div class="loading">Đang tải chi tiết...</div></div>
    </div>
    <div class="round-info">
      <p id="round-summary">Đang tải...</p>
      <button class="next-round-btn" onclick="sendCommand('Tiến vào vòng tiếp theo')">▶️ Tiến vào vòng tiếp theo</button>
    </div>
