  </div>

  <script>
    const exampleXML = `<content>$1</content>`;

    // ========== Hàm gửi lệnh ==========
    function sendCommand(command) {
      console.log('Gửi lệnh:', command);
      if (typeof triggerSlash === 'function') {
        triggerSlash(`/send ${command}|/trigger`);
        return;
      }
      if (typeof SillyTavern !== 'undefined' && SillyTavern.getContext) {
        const context = SillyTavern.getContext();
        if (context && context.sendMessage) {
          context.sendMessage(command, 'user');
          return;
        }
      }
      try {
        const textarea = document.querySelector('#send_textarea');
        if (textarea) {
          textarea.value = command;
          textarea.dispatchEvent(new Event('input', { bubbles: true }));
          setTimeout(() => {
            const sendBtn = document.querySelector('#send_but');
            if (sendBtn) sendBtn.click();
          }, 100);
          return;
        }
      } catch (e) { console.error('Gửi thất bại:', e); }
      alert('Vui lòng gửi thủ công: ' + command);
    }

    // ========== Hàm phân tích ==========
    function parseData(xmlText) {
      console.log("Bắt đầu phân tích dữ liệu...");
      console.log("Độ dài XML:", xmlText.length);

      const data = {
        events: { year: '', family: '', months: [] },
        family: { name: '', members: [] },
        current: {},
        variables: { assets: {}, industries: [], shop: { female: [], items: [], business: [] }, loan: {}, auction: '', trades: {} },
        deaths: [],
        detailed: ''
      };

      try {
        // ========== Trích xuất Event_Interface (Hiển thị trực tiếp nội dung gốc) ==========
        const eventMatch = xmlText.match(/<Event_Interface>([\s\S]*?)<\/Event_Interface>/i);
        if (eventMatch) {
          console.log("Tìm thấy Event_Interface");
          data.eventsRaw = eventMatch[1].trim();
        }


        // ========== Trích xuất Family_Records ==========
        const familyMatch = xmlText.match(/<Family_Records>([\s\S]*?)<\/Family_Records>/i);
        if (familyMatch) {
          console.log("Tìm thấy Family_Records");
          const famText = familyMatch[1];

          // Trích xuất tên gia tộc
          const nameMatch = famText.match(/\[📋[:：]\s*(\S+?)Hồ sơ thành viên gia tộc\]/);
          if (nameMatch) data.family.name = nameMatch[1];

          // Phân tách khối thành viên
          const memberBlocks = famText.split(/(?=👨|👩)/);
          memberBlocks.forEach(block => {
            if (!block.trim()) return;
            const isMale = block.startsWith('👨');

            // Phân tích thông tin phần đầu
            const headerMatch = block.match(/[👨👩]\[([^\]]+)\]\s*([^(\n]+)\(([0-9.]+)\)/);
            if (!headerMatch) return;

            const member = {
              id: headerMatch[1],
              name: headerMatch[2].trim(),
              age: headerMatch[3],
              gender: isMale ? 'male' : 'female',
              body: '', organ: '', history: '', fertility: '', mental: '', favor: '', level: '', skills: '', traits: '', personality: ''
            };

            // Phân tích các dữ liệu khác - Tương thích dấu hai chấm toàn/bán giác
            const bodyMatch = block.match(/├Thân thể[:：]\s*([^\n]+)/);
            if (bodyMatch) member.body = bodyMatch[1].trim();

            const organMatch = block.match(/├Cơ quan sinh dục[:：]\s*([^\n]+)/);
            if (organMatch) member.organ = organMatch[1].trim();

            const histMatch = block.match(/├Lịch sử tình dục[:：]\s*([^\n]+)/);
            if (histMatch) member.history = histMatch[1].trim();

            const fertMatch = block.match(/├Sinh sản[:：]\s*([^\n]+)/);
            if (fertMatch) member.fertility = fertMatch[1].trim();

            const mentalMatch = block.match(/├Tâm lý[:：]\s*([^\n]+)/);
            if (mentalMatch) member.mental = mentalMatch[1].trim();

            const favorMatch = block.match(/├Hào cảm[:：]\s*([^\n]+)/);
            if (favorMatch) member.favor = favorMatch[1].trim();

            const levelMatch = block.match(/├Cấp độ[:：]\s*([^\n]+)/);
            if (levelMatch) member.level = levelMatch[1].trim();

            const skillMatch = block.match(/├Kỹ năng[:：]\s*([^\n]+)/);
            if (skillMatch) member.skills = skillMatch[1].trim();

            const traitMatch = block.match(/├Đặc chất[:：]\s*([^\n]+)/);
            if (traitMatch) member.traits = traitMatch[1].trim();

            const persMatch = block.match(/└Tính cách[:：]\s*([^\n]+)/);
            if (persMatch) member.personality = persMatch[1].trim();

            data.family.members.push(member);
          });
          console.log("Phân tích thành viên hoàn tất, số người:", data.family.members.length);
        }

        // ========== Trích xuất Current_Information ==========
        const curMatch = xmlText.match(/<Current_Information>([\s\S]*?)<\/Current_Information>/i);
        if (curMatch) {
          console.log("Tìm thấy Current_Information");
          const curText = curMatch[1];

          // Thông tin thời gian - Tương thích dấu hai chấm toàn/bán giác
          const timeMatch = curText.match(/Thời gian hiện tại[:：]\s*([^\|｜]+)[\|｜]\s*Vòng[:：]\s*([^\n]+)/);
          if (timeMatch) {
            data.current.time = timeMatch[1].trim();
            data.current.round = timeMatch[2].trim();
          }

          const seasonMatch = curText.match(/Mùa[:：]\s*([^\|｜]+)[\|｜]\s*Tiết khí[:：]\s*([^\n]+)/);
          if (seasonMatch) {
            data.current.season = seasonMatch[1].trim();
            data.current.solar = seasonMatch[2].trim();
          }

          // Thông tin gia tộc
          const fnMatch = curText.match(/Tên gia tộc[:：]\s*([^\n]+)/);
          if (fnMatch) data.current.familyName = fnMatch[1].trim();

          const masterMatch = curText.match(/Chủ gia tộc[:：]\s*([^\[]+)\[([^\]]+)\]/);
          if (masterMatch) {
            data.current.master = masterMatch[1].trim();
            data.current.masterId = masterMatch[2].trim();
          }

          const levelMatch = curText.match(/Cấp độ gia tộc[:：]\s*([^\|｜]+)[\|｜]\s*Giá trị danh tiếng[:：]\s*([^\n]+)/);
          if (levelMatch) {
            data.current.level = levelMatch[1].trim();
            data.current.fame = levelMatch[2].trim();
          }

          const fameDescMatch = curText.match(/Danh tiếng gia tộc[:：]\s*([^\n]+)/);
          if (fameDescMatch) data.current.fameDesc = fameDescMatch[1].trim();

          const indMatch = curText.match(/Sản nghiệp gia tộc[:：]\s*([^\n]+)/);
          if (indMatch) data.current.industries = indMatch[1].trim();

          const credMatch = curText.match(/Uy tín thương mại[:：]\s*([^\n]+)/);
          if (credMatch) data.current.credit = credMatch[1].trim();

          const mottoMatch = curText.match(/Châm ngôn gia tộc[:：]\s*"([^"]+)"/);
          if (mottoMatch) data.current.motto = mottoMatch[1];

          const estMatch = curText.match(/Thời gian thành lập[:：]\s*([^\|｜]+)[\|｜]\s*Tồn tại[:：]\s*([^\n]+)/);
          if (estMatch) {
            data.current.established = estMatch[1].trim();
            data.current.duration = estMatch[2].trim();
          }

          // Thống kê nhân khẩu
          const popMatch = curText.match(/Tổng nhân khẩu[:：]\s*(\d+)người\s*\(Nam giới[:：]\s*(\d+)người\s*[\|｜]\s*Nữ giới[:：]\s*(\d+)người\)/);
          if (popMatch) {
            data.current.totalPop = popMatch[1];
            data.current.malePop = popMatch[2];
            data.current.femalePop = popMatch[3];
          }

          // Tổng quan tài sản
          const flowMatch = curText.match(/Vốn lưu động[:：]\s*(\d+)Vàng/);
          if (flowMatch) data.current.flowMoney = flowMatch[1];

          const fixMatch = curText.match(/Tài sản cố định[:：]\s*(\d+)Vàng/);
          if (fixMatch) data.current.fixedAssets = fixMatch[1];

          const totalMatch = curText.match(/Tổng tài sản[:：]\s*(\d+)Vàng/);
          if (totalMatch) data.current.totalAssets = totalMatch[1];

          const incMatch = curText.match(/Thu nhập tháng[:：]\s*\+?(\d+)Vàng\s*[\|｜]\s*Chi tiêu tháng[:：]\s*-?(\d+)Vàng\s*[\|｜]\s*Thu nhập ròng[:：]\s*([^\n]+)/);
          if (incMatch) {
            data.current.monthIncome = incMatch[1];
            data.current.monthExpense = incMatch[2];
            data.current.netIncome = incMatch[3].trim();
          }

          // Trạng thái gia tộc
          const prosMatch = curText.match(/Độ phồn vinh[:：]\s*(\d+)\/(\d+)/);
          if (prosMatch) data.current.prosperity = { cur: prosMatch[1], max: prosMatch[2] };

          const stabMatch = curText.match(/Độ ổn định[:：]\s*(\d+)\/(\d+)/);
          if (stabMatch) data.current.stability = { cur: stabMatch[1], max: stabMatch[2] };

          const milMatch = curText.match(/Lực lượng quân sự[:：]\s*(\d+)\/(\d+)/);
          if (milMatch) data.current.military = { cur: milMatch[1], max: milMatch[2] };

          const culMatch = curText.match(/Giá trị văn hóa[:：]\s*(\d+)\/(\d+)/);
          if (culMatch) data.current.culture = { cur: culMatch[1], max: culMatch[2] };
        }

        // ========== Trích xuất Family_variables ==========
        const varMatch = xmlText.match(/<Family_variables>([\s\S]*?)<\/Family_variables>/i);
        if (varMatch) {
          console.log("Tìm thấy Family_variables");
          const varText = varMatch[1];

          // Chi tiết tài sản
          const flowMatch = varText.match(/Vốn lưu động[:：]\s*(\d+)Vàng/);
          if (flowMatch) data.variables.assets.flow = flowMatch[1];

          const fixMatch = varText.match(/Tài sản cố định[:：]\s*(\d+)Vàng/);
          if (fixMatch) data.variables.assets.fixed = fixMatch[1];

          const totalMatch = varText.match(/Tổng tài sản[:：]\s*(\d+)Vàng/);
          if (totalMatch) data.variables.assets.total = totalMatch[1];

          const debtMatch = varText.match(/Nợ nần[:：]\s*(\d+)Vàng/);
          if (debtMatch) data.variables.assets.debt = debtMatch[1];

          const netMatch = varText.match(/Tài sản ròng[:：]\s*(\d+)Vàng/);
          if (netMatch) data.variables.assets.net = netMatch[1];

          // Danh sách sản nghiệp
          const indRegex = /•\s*([^\|｜]+)[\|｜]\s*([^\|｜]+)[\|｜]\s*\+?(\d+)Vàng\/tháng\s*[\|｜]\s*([^\|｜]+)[\|｜]\s*([^\n]+)/g;
          let indM;
          while ((indM = indRegex.exec(varText)) !== null) {
            data.variables.industries.push({
              name: indM[1].trim(),
              type: indM[2].trim(),
              income: indM[3],
              risk: indM[4].trim(),
              status: indM[5].trim()
            });
          }

          // Thị trường nữ giới
          const femaleMatch = varText.match(/【Thị trường nữ giới】[^\n]*\n([\s\S]*?)(?=【Cửa hàng đạo cụ】|【Đầu tư sản nghiệp】|\[Hệ thống đặc biệt\]|$)/);
          if (femaleMatch) {
            const femRegex = /([A-Z]-\d+)\|([^|]+)\|(\d+)Vàng\|([^\n]+)/g;
            let fm;
            while ((fm = femRegex.exec(femaleMatch[1])) !== null) {
              data.variables.shop.female.push({
                id: fm[1],
                name: fm[2].trim(),
                price: fm[3],
                desc: fm[4].trim()
              });
            }
          }

          // Cửa hàng đạo cụ
          const itemMatch = varText.match(/【Cửa hàng đạo cụ】[^\n]*\n([\s\S]*?)(?=【Đầu tư sản nghiệp】|\[Hệ thống đặc biệt\]|$)/);
          if (itemMatch) {
            const itemRegex = /([A-Z]-\d+)\|([^|]+)\|(\d+)Vàng\|([^\n]+)/g;
            let im;
            while ((im = itemRegex.exec(itemMatch[1])) !== null) {
              data.variables.shop.items.push({
                id: im[1],
                name: im[2].trim(),
                price: im[3],
                desc: im[4].trim()
              });
            }
          }

          // Đầu tư sản nghiệp
          const bizMatch = varText.match(/【Đầu tư sản nghiệp】[^\n]*\n([\s\S]*?)(?=\[Hệ thống đặc biệt\]|$)/);
          if (bizMatch) {
            const bizRegex = /([A-Z]-\d+)\|([^|]+)\|(\d+)Vàng\|([^\n]+)/g;
            let bm;
            while ((bm = bizRegex.exec(bizMatch[1])) !== null) {
              data.variables.shop.business.push({
                id: bm[1],
                name: bm[2].trim(),
                price: bm[3],
                desc: bm[4].trim()
              });
            }
          }

          // Thông tin cho vay
          const loanMatch = varText.match(/Hạn mức cho vay[:：]\s*(\d+)Vàng/);
          if (loanMatch) data.variables.loan.limit = loanMatch[1];

          const rateMatch = varText.match(/Lãi suất hiện tại[:：]\s*([^\n]+)/);
          if (rateMatch) data.variables.loan.rate = rateMatch[1].trim();

          const loanedMatch = varText.match(/Khoản đã vay[:：]\s*(\d+)Vàng/);
          if (loanedMatch) data.variables.loan.loaned = loanedMatch[1];

          // Nhà đấu giá
          const auctionMatch = varText.match(/【Nhà đấu giá】\s*\n([^\n\[]+)/);
          if (auctionMatch) data.variables.auction = auctionMatch[1].trim();

          // Ghi chép giao dịch
          const buyMatch = varText.match(/Lượt này đã mua[:：]\s*([^\n]+)/);
          if (buyMatch) data.variables.trades.buy = buyMatch[1].trim();

          const sellMatch = varText.match(/Lượt này đã bán[:：]\s*([^\n]+)/);
          if (sellMatch) data.variables.trades.sell = sellMatch[1].trim();
        }

        // ========== Trích xuất Notification_System ==========
        const deathMatch = xmlText.match(/<Notification_System>([\s\S]*?)<\/Notification_System>/i);
        if (deathMatch) {
          console.log("Tìm thấy Notification_System");
          const deathText = deathMatch[1];
          const deathRegex = /([^\n\/]+)\/([NamNữ])\/(\d+)\s*\(([^)]+)\)/g;
          let dm;
          while ((dm = deathRegex.exec(deathText)) !== null) {
            data.deaths.push({
              name: dm[1].trim(),
              gender: dm[2],
              age: dm[3],
              detail: dm[4].trim()
            });
          }
        }

        // ========== Trích xuất Detailed_events ==========
        const detailedMatch = xmlText.match(/<Detailed_events>([\s\S]*?)<\/Detailed_events>/i);
        if (detailedMatch) {
          data.detailed = detailedMatch[1].trim();
        }

        console.log("Phân tích hoàn tất:", data);
        return data;

      } catch (error) {
        console.error('Lỗi phân tích:', error);
        return data;
      }
    }

